  1	/**
  2	 * 简化版 API 客户端 - 适配 SkillHub Lite 后端
  3	 */
  4	
  5	const API_BASE = '/api';
  6	
  7	export interface Skill {
  8	  id: string;
  9	  name: string;
 10	  slug: string;
 11	  description: string;
 12	  readme_content?: string;
 13	  author_name: string;
 14	  author_email: string;
 15	  admin_key_hash?: string;
 16	  download_count: number;
 17	  latest_version: string;
 18	  created_at: string;
 19	  updated_at: string;
 20	}
 21	
 22	export interface SkillVersion {
 23	  id: string;
 24	  skill_id: string;
 25	  version: string;
 26	  tag: string | null;
 27	  is_latest: boolean;
 28	  storage_path: string;
 29	  file_size: number;
 30	  file_hash: string;
 31	  created_at: string;
 32	}
 33	
 34	export interface SkillDetail extends Skill {
 35	  versions: SkillVersion[];
 36	}
 37	
 38	export interface PageResponse<T> {
 39	  content: T[];
 40	  totalElements: number;
 41	  totalPages: number;
 42	  size: number;
 43	  number: number;
 44	}
 45	
 46	export interface ApiResponse<T> {
 47	  success: boolean;
 48	  data: T;
 49	  message?: string;
 50	}
 51	
 52	// 获取技能列表
 53	export async function getSkills(params?: { 
 54	  page?: number; 
 55	  size?: number; 
 56	  tag?: string 
 57	}): Promise<ApiResponse<PageResponse<Skill>>> {
 58	  const query = new URLSearchParams();
 59	  if (params?.page !== undefined) query.set('page', String(params.page));
 60	  if (params?.size !== undefined) query.set('size', String(params.size));
 61	  if (params?.tag) query.set('tag', params.tag);
 62	  
 63	  const response = await fetch(`${API_BASE}/skills?${query}`);
 64	  if (!response.ok) throw new Error('Failed to fetch skills');
 65	  return response.json();
 66	}
 67	
 68	// 获取技能详情
 69	export async function getSkill(slug: string): Promise<ApiResponse<SkillDetail>> {
 70	  const response = await fetch(`${API_BASE}/skills/${slug}`);
 71	  if (!response.ok) throw new Error('Failed to fetch skill');
 72	  return response.json();
 73	}
 74	
 75	// 搜索技能
 76	export async function searchSkills(q: string): Promise<ApiResponse<{ content: Skill[]; totalElements: number }>> {
 77	  const response = await fetch(`${API_BASE}/search?q=${encodeURIComponent(q)}`);
 78	  if (!response.ok) throw new Error('Failed to search skills');
 79	  return response.json();
 80	}
 81	
 82	// 发布技能
 83	export async function publishSkill(formData: FormData): Promise<ApiResponse<{
 84	  id: string;
 85	  name: string;
 86	  slug: string;
 87	  version: string;
 88	  downloadUrl: string;
 89	}>> {
 90	  const response = await fetch(`${API_BASE}/skills`, {
 91	    method: 'POST',
 92	    body: formData,
 93	  });
 94	  
 95	  if (!response.ok) {
 96	    const error = await response.json();
 97	    throw new Error(error.detail || 'Failed to publish skill');
 98	  }
 99	  return response.json();
100	}
101	
102	// 发布新版本
103	export async function publishVersion(
104	  slug: string, 
105	  formData: FormData
106	): Promise<ApiResponse<{
107	  skillId: string;
108	  version: string;
109	  tag: string;
110	  downloadUrl: string;
111	}>> {
112	  const response = await fetch(`${API_BASE}/skills/${slug}/versions`, {
113	    method: 'POST',
114	    body: formData,
115	  });
116	  
117	  if (!response.ok) {
118	    const error = await response.json();
119	    throw new Error(error.detail || 'Failed to publish version');
120	  }
121	  return response.json();
122	}
123	
124	// 删除技能（无限制）
125	export async function deleteSkill(slug: string): Promise<ApiResponse<{ message: string }>> {
126	  const response = await fetch(`${API_BASE}/skills/${slug}`, {
127	    method: 'DELETE',
128	  });
129	  
130	  if (!response.ok) {
131	    const error = await response.json();
132	    throw new Error(error.detail || 'Failed to delete skill');
133	  }
134	  return response.json();
135	}
136	
137	// 获取下载链接
138	export function getDownloadUrl(slug: string, version?: string): string {
139	  if (version) {
140	    return `${API_BASE}/skills/${slug}/download?version=${encodeURIComponent(version)}`;
141	  }
142	  return `${API_BASE}/skills/${slug}/download`;
143	}
144	
145	// 健康检查
146	export async function healthCheck(): Promise<{ status: string; version: string }> {
147	  const response = await fetch('/health');
148	  if (!response.ok) throw new Error('Health check failed');
149	  return response.json();
150	}

